import React, {createContext, useContext, useEffect, useMemo, useRef, useState} from 'react';
import SingleFileUploader from '../SingleFileUploader';
import SingleImageUploader from '../SingleImageUploader';
import MultipleFileUploader from '../MultipleFileUploader';
import MultipleImageUploader from '../MultipleImageUploader';
import {getType, type IFileUploader, type IMemes} from '@lmb-it/kitsconcerto-types';
import {Flex} from "../../../_compat";
import {AnyFile} from "../../../utils";

type HtmlFile = File;

interface IFileUploaderContextValues {
    onChangeAnyFileUploader(files: HtmlFile[] | FileList): void;
    removeFile(fileIndex: number): () => void;
    onInvalidInput(errors: any): void;
    selectedFiles: HtmlFile[];
    selectedInitialFiles: string[];
    placeholder?: string;
    disabled?: boolean;
    isClassicUploader: boolean;
    limit: number;
    acceptedMemes: string[];
    files: { name: string; ext: string; shortName: string; file: { uri: string } | File | string }[];
    id: string;
    previewWidth?: string | number;
    previewHeight?: string | number;
}

export const FileUploaderContext = createContext<IFileUploaderContextValues>({
    onChangeAnyFileUploader: () => {},
    removeFile: () => () => {},
    onInvalidInput: () => {},
    disabled: false,
    limit: 1,
    isClassicUploader: true,
    selectedInitialFiles: [],
    selectedFiles: [],
    acceptedMemes: [],
    files: [],
    id: "",
    previewWidth: undefined,
    previewHeight: undefined,
});

const base64ToJson = (base64Image: string) => {
    const splitImage = base64Image.split(',');
    let imageType = '';
    if (splitImage.length) {
        const t = splitImage[0]?.split(':');
        if (t) imageType = t[1]?.split(';')[0] ?? '';
    }
    return {type: imageType, base64: splitImage[1] ?? ''};
};

const jsonToBase64 = (base64: string, memeType: string) =>
    `data:${memeType};base64,${base64}`;

const getBase64 = (file: File): Promise<{ filename: string; base64: string; type: string }> => {
    return new Promise((resolve, reject) => {
        const filename = file.name.replace(/\.[^/.]+$/, "");
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = () => {
            const v = reader.result as string;
            resolve({filename, ...base64ToJson(v)});
        };
        reader.onerror = () => reject(null);
    });
};

const MainUploaderWeb = (props: IFileUploader<File>) => {
    const {
        acceptedTypes,
        type,
        classicUploader = true,
        limit = 1,
        onError,
        onFocus,
        placeholder,
        defaultValue,
        multiple,
        isJsonOutput = true,
        onChange,
        value,
        name,
        disabled,
        maxFileSize,
        minFileSize,
        children,
        previewWidth,
        previewHeight,
    } = props;

    const initialValueSynced = useRef(false);
    const [selectedFilesAsBase64, setSelectedFilesAsBase64] = useState<{
        filename: string; base64: string; type: string;
    }[]>([]);
    const [selectedFiles, setSelectedFiles] = useState<File[]>([]);
    const [selectedInitialFiles, setSelectedInitialFiles] = useState<string[]>([]);

    const isImageSingle = type === "Image" && !multiple;
    const isImageMultiple = type === "Image" && !!multiple;
    const isFileSingle = type === "File" && !multiple;
    const isFileMultiple = type === "File" && !!multiple;
    const isOneFile = isImageSingle || isFileSingle || limit < 2;

    const onInvalidInput = (errors: any) => onError?.(errors);

    const onChangeAnyFileUploader = (files: HtmlFile[] | FileList) => {
        if (disabled) return;
        const filesList: HtmlFile[] = [];

        for (let i = 0; i < files.length; i++) {
            const f = files[i];
            if (!f) continue;
            const fileSize = f.size / 1000;

            if ((!maxFileSize || fileSize <= maxFileSize) && (!minFileSize || fileSize >= minFileSize)) {
                filesList.push(f);
                onInvalidInput('clear');
            } else {
                let message = `File "${f.name}" is `;
                if (maxFileSize && fileSize > maxFileSize) {
                    message += `too large. Maximum allowed is ${maxFileSize / 1000} MB.`;
                } else if (minFileSize && fileSize < minFileSize) {
                    message += `too small. Minimum allowed is ${minFileSize / 1000} MB.`;
                }
                onInvalidInput(message);
            }
        }

        if (isOneFile) {
            if (filesList.length) setSelectedFiles(filesList.slice(0, 1));
        } else {
            setSelectedFiles(prev => [...prev, ...filesList]);
        }
    };

    const removeFile = (fileIndex: number) => () => {
        if (fileIndex < selectedInitialFiles.length) {
            setSelectedInitialFiles(prev => prev.filter((_, i) => i !== fileIndex));
        } else {
            const editIndex = fileIndex - selectedInitialFiles.length;
            setSelectedFiles(prev => prev.filter((_, i) => i !== editIndex));
            setSelectedFilesAsBase64(prev => prev.filter((_, i) => i !== editIndex));
        }
    };

    // Convert files to base64
    useEffect(() => {
        if (selectedFiles.length === 0) {
            setSelectedFilesAsBase64([]);
            return;
        }
        Promise.all(selectedFiles.map(f => getBase64(f)))
            .then(converted => setSelectedFilesAsBase64(converted))
            .catch(() => {});
    }, [selectedFiles]);

    // Emit onChange when base64 conversion completes or files change
    useEffect(() => {
        if (disabled) return;
        // Wait for base64 conversion to complete
        if (selectedFiles.length > 0 && selectedFilesAsBase64.length !== selectedFiles.length) return;

        if (selectedFiles.length === 0 && selectedInitialFiles.length === 0) {
            onChange?.([], []);
        } else {
            onChange?.(selectedFiles, selectedFilesAsBase64);
        }
    }, [selectedFilesAsBase64, selectedInitialFiles]);

    // defaultValue sync
    useEffect(() => {
        if (defaultValue) {
            setSelectedInitialFiles(Array.isArray(defaultValue) ? defaultValue : [defaultValue]);
        }
    }, [defaultValue]);

    // controlled value sync (first time only)
    useEffect(() => {
        if (initialValueSynced.current) return;
        if (value) {
            setSelectedInitialFiles(Array.isArray(value) ? value : [value]);
        }
        initialValueSynced.current = true;
    }, [value]);

    const getAcceptedFiles = useMemo(() => {
        return acceptedTypes ? (acceptedTypes as IMemes[]).map(ext => getType(ext)) : [];
    }, [acceptedTypes]);

    // Build display array
    const display = useMemo(() => {
        const allFiles: (File | string | { filename: string; base64: string; type: string })[] = [
            ...selectedInitialFiles,
            ...(isJsonOutput ? selectedFilesAsBase64 : selectedFiles),
        ];

        return allFiles.map((file) => {
            if (typeof file === "string") {
                return {
                    ...AnyFile.parts(file),
                    shortName: AnyFile.shortName(file),
                    file: {uri: file}
                };
            } else if (file instanceof File) {
                return {
                    ...AnyFile.parts(file.name),
                    shortName: AnyFile.shortName(file.name),
                    file
                };
            } else {
                return {
                    ...AnyFile.parts(file.filename),
                    shortName: AnyFile.shortName(file.filename),
                    file: jsonToBase64(file.base64, file.type)
                };
            }
        });
    }, [selectedFilesAsBase64, selectedInitialFiles, selectedFiles, isJsonOutput]);

    /** Replace entire file selection (for template's update callback) */
    const updateFiles = (files: HtmlFile | HtmlFile[]) => {
        const arr = Array.isArray(files) ? files : [files];
        setSelectedFiles(arr);
        setSelectedInitialFiles([]);
        setSelectedFilesAsBase64([]);
    };

    const hiddenInputRef = useRef<HTMLInputElement>(null);
    const isImage = type === "Image";

    const browse = () => {
        if (disabled) return;
        hiddenInputRef.current?.click();
    };

    const handleHiddenInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files) {
            onChangeAnyFileUploader(e.target.files);
        }
        // Reset so the same file can be picked again
        e.target.value = '';
    };

    const contextValue = {
        onChangeAnyFileUploader,
        removeFile,
        onInvalidInput,
        selectedFiles,
        selectedInitialFiles,
        disabled,
        limit,
        placeholder,
        isClassicUploader: classicUploader,
        acceptedMemes: getAcceptedFiles,
        files: display,
        id: name ?? '',
        previewWidth,
        previewHeight,
    };

    return (
        <FileUploaderContext.Provider value={contextValue}>
            <Flex onFocus={onFocus} w={"full"}>
                {children ? (
                    <>
                        <input
                            ref={hiddenInputRef}
                            type="file"
                            accept={getAcceptedFiles.join(',')}
                            multiple={!isOneFile}
                            style={{display: 'none'}}
                            onChange={handleHiddenInputChange}
                        />
                        {children({
                            values: selectedFiles,
                            browse,
                            update: updateFiles,
                            remove: (index: number) => removeFile(index)(),
                            type: isImage ? 'image' : 'file',
                            isMultiple: !isOneFile,
                        })}
                    </>
                ) : (
                    <>
                        {isImageSingle && <SingleImageUploader/>}
                        {isFileSingle && <SingleFileUploader/>}
                        {isFileMultiple && <MultipleFileUploader/>}
                        {isImageMultiple && <MultipleImageUploader/>}
                    </>
                )}
            </Flex>
        </FileUploaderContext.Provider>
    );
};

export default MainUploaderWeb;

export const useUploader = () => useContext(FileUploaderContext);
